/**
 * SSEConnection — Manages SSE connection to overlay event stream with exponential backoff.
 * 
 * Requirements: 2.1, 2.6
 */

export interface OverlayRuntimePacketV1 {
  header: { type: string; eventId?: string };
  payload: Record<string, unknown>;
}

export interface SSEConnectionOptions {
  publicId: string;
  onPacket: (packet: OverlayRuntimePacketV1) => void;
  onConnect?: () => void;
  onDisconnect?: () => void;
}

export class SSEConnection {
  private eventSource: EventSource | null = null;
  private reconnectTimer: number | null = null;
  private attemptCount: number = 0;
  private options: SSEConnectionOptions;

  constructor(options: SSEConnectionOptions) {
    this.options = options;
  }

  connect(): void {
    // Cancel any pending reconnect
    if (this.reconnectTimer !== null) {
      clearTimeout(this.reconnectTimer);
      this.reconnectTimer = null;
    }

    // Close existing connection if any
    if (this.eventSource !== null) {
      this.eventSource.close();
    }

    const url = `/api/overlays/public/${this.options.publicId}/events/stream`;
    this.eventSource = new EventSource(url);

    this.eventSource.onopen = () => {
      // Reset attempt counter on successful connection
      this.attemptCount = 0;
      if (this.options.onConnect) {
        this.options.onConnect();
      }
    };

    this.eventSource.onmessage = (event) => {
      try {
        const packet = JSON.parse(event.data) as OverlayRuntimePacketV1;
        this.options.onPacket(packet);
      } catch (error) {
        console.error('[SSEConnection] Failed to parse message:', error);
      }
    };

    this.eventSource.onerror = () => {
      // Close the failed connection
      if (this.eventSource !== null) {
        this.eventSource.close();
        this.eventSource = null;
      }

      // Schedule reconnect with exponential backoff
      // delay = min(2^attempt * 1000, 30_000) ms
      const delay = Math.min(Math.pow(2, this.attemptCount) * 1000, 30_000);
      this.attemptCount++;

      console.log(`[SSEConnection] Reconnecting in ${delay}ms (attempt ${this.attemptCount})`);

      this.reconnectTimer = window.setTimeout(() => {
        this.reconnectTimer = null;
        this.connect();
      }, delay);
    };
  }

  disconnect(): void {
    // Cancel any pending reconnect
    if (this.reconnectTimer !== null) {
      clearTimeout(this.reconnectTimer);
      this.reconnectTimer = null;
    }

    // Close the EventSource
    if (this.eventSource !== null) {
      this.eventSource.close();
      this.eventSource = null;
    }

    // Call onDisconnect callback
    if (this.options.onDisconnect) {
      this.options.onDisconnect();
    }
  }
}
